INSERT INTO questions (discipline_id, dimension_id, theme_id, question_text, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, difficulty, specialty, created_by) VALUES
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Um paciente de 60 anos, em telessaúde, queixa-se de febre e calafrios há 3 dias. Ele tem cateter venoso central inserido há 2 semanas para nutrição parenteral. A equipe de enfermagem reporta sinais flogísticos no local. Qual a conduta imediata?', 'Trocar o curativo e manter o cateter, com cobertura com cefalexina oral.', 'Retirar o cateter, coletar hemoculturas, iniciar antibioticoterapia empírica intravenosa e encaminhar ao hospital.', 'Iniciar vancomicina oral e manter observação domiciliar.', 'Solicitar ultrassom local e aguardar resultado.', NULL, 'b', 'A presença de sinais flogísticos (inflamação) no sítio de inserção de um cateter venoso central, associada a sintomas sistêmicos como febre e calafrios, é sugestiva de Infecção de Corrente Sanguínea Relacionada a Cateter (ICSRC), uma condição grave. A conduta padrão é a remoção da fonte da infecção (o cateter), a coleta de culturas (hemoculturas) para guiar a terapia e o início imediato de antibioticoterapia intravenosa empírica devido ao risco de sepse. A telessaúde, neste caso, serve para identificar a emergência e garantir o encaminhamento hospitalar imediato.', 'hard', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Durante teleatendimento, um paciente relata ter sido mordido por um cão desconhecido há 4 horas. A ferida é profunda em antebraço e com sangramento ativo. Ele não sabe a situação vacinal do animal. Qual o manejo?', 'Orientar lavagem com água e sabão, aplicar soro antirrábico e vacina anti-rábica em esquema de 5 doses, e encaminhar para sutura.', 'Apenas limpar e cobrir, pois raiva é rara no Brasil.', 'Iniciar antibioticoterapia profilática e vacina antitetânica.', 'Encaminhar imediatamente ao serviço de emergência para avaliação da ferida e  profilaxia de raiva (soro + vacina), pois a telessaúde não pode manejar ferimentos profundos.', NULL, 'd', 'Feridas profundas e com sangramento ativo, especialmente mordeduras de animais com status vacinal desconhecido, são emergências que extrapolam a capacidade de manejo da telessaúde. O paciente necessita de avaliação presencial para limpeza adequada, desbridamento e avaliação da profilaxia para raiva (que inclui soro e vacina, a depender da gravidade e localização da ferida) e tétano. A função da telemedicina é reconhecer a gravidade, orientar os primeiros socorros (lavagem exaustiva com água e sabão) e encaminhar imediatamente ao serviço de emergência.', 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Uma jovem de 19 anos, em teleconsulta, apresenta múltiplas pápulas, vesículas e pústulas no tronco e face, algumas crostosas, associadas a febre (38,5°', 'Herpes zoster – aciclovir 800 mg 5x/dia por 7 dias.', 'Varicela – aciclovir 800 mg 5x/dia por 7 dias, orientação de isolamento e notificação compulsória.', 'Impetigo bolhoso – cefalexina 500 mg 6/6h.', 'Reação alérgica – anti-histamínico e corticoide tópico.', NULL, 'b', 'O quadro de lesões cutâneas polimórficas (em diferentes estágios de evolução: pápulas, vesículas, pústulas e crostas), distribuídas de forma centrípeta (iniciando no tronco/face e espalhando para membros), associado a febre e prurido em paciente sem história prévia, é a apresentação clássica da varicela (catapora). Em pacientes com mais de 13 anos, o tratamento com aciclovir oral é recomendado para diminuir a intensidade e a duração dos sintomas, além de reduzir o risco de complicações. O isolamento respiratório e a notificação compulsória são medidas de saúde pública obrigatórias.', 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Um paciente de 50 anos com HIV (carga viral indetectável, CD4 350) relata em teleconsulta dor ao urinar e corrimento uretral purulento. Nega febre. Qual a etiologia mais provável e conduta inicial?', 'Infecção do trato urinário – nitrofurantoína.', 'Gonorreia – ceftriaxona 500 mg IM + azitromicina 1 g VO.', 'Clamídia – azitromicina 1 g VO.', 'Prostatite – ciprofloxacino 500 mg 12/12h.', NULL, 'b', 'O corrimento uretral purulento é o sintoma cardinal da uretrite gonocócica. Devido à alta frequência de coinfecção com Chlamydia trachomatis (que pode ser assintomática ou causar corrimento claro), as diretrizes atuais recomendam o tratamento sindrômico com dupla cobertura: Ceftriaxona para a gonorreia e Azitromicina para a clamídia. O estado de imunossupressão do paciente com HIV não altera a primeira linha de tratamento para esta IST.', 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Em telemedicina, ao atender uma criança de 3 anos com febre alta há 2 dias, tosse e prostração, a mãe envia foto do pescoço mostrando placas branco-acinzentadas nas amígdalas e base da língua, com dificuldade para deglutir. Qual a suspeita e conduta?', 'Faringite viral – sintomáticos.', 'Mononucleose infecciosa – repouso e evitar esforço.', 'Difteria – administrar antitoxina diftérica e antibiótico (azitromicina), além de notificação compulsória.', 'Amigdalite bacteriana – amoxicilina 50 mg/kg/dia.', NULL, 'a', NULL, 'hard', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Paciente de 40 anos, com suspeita de dengue, realiza teleconsulta e apresenta prova do laço positiva (20 petéquias/cm²). Sem outros sinais de alarme. Qual a classificação e conduta?', 'Dengue com sinais de alarme – internação.', 'Dengue sem sinais de alarme – manejo ambulatorial com hidratação e reavaliação em 24h.', 'Dengue grave – UTI.', 'Chikungunya – sintomáticos.', NULL, 'b', 'De acordo com a classificação do Ministério da Saúde, a prova do laço positiva indica fragilidade capilar, mas não é, isoladamente, um sinal de alarme. Na ausência de outros sinais de alarme (como dor abdominal intensa, vômitos persistentes, sangramentos de mucosas, hipotensão), o paciente é classificado no Grupo B (ou "dengue sem sinais de alarme") e pode ser manejado em nível ambulatorial, com hidratação oral vigorosa e orientação estrita para retorno se surgirem sinais de alarme.', 'easy', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Teleconsulta: paciente de 60 anos, em tratamento para tuberculose latente com isoniazida há 2 meses, queixa-se de parestesia em mãos e pés. Qual a conduta?', 'Suspender isoniazida imediatamente.', 'Adicionar piridoxina (vitamina B6) 50 mg/dia e manter isoniazida.', 'Substituir isoniazida por rifampicina.', 'Aumentar a dose de isoniazida.', NULL, 'a', NULL, 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Durante teleconsulta, uma paciente de 32 semanas de gestação relata febre e contrações uterinas. Ela estava em uso de antirretrovirais para HIV (carga viral indetectável). Qual a orientação?', 'Orientar repouso e tomar paracetamol.', 'Encaminhar à maternidade para avaliação de trabalho de parto prematuro e manejo da terapia antirretroviral durante o parto.', 'Aumentar a dose de antirretrovirais.', 'Realizar toque vaginal em casa, guiado por vídeo.', NULL, 'e', NULL, 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac'),
('f3965736-aa39-43dd-8b6a-b2076ac4c596', 'e9fd508c-7156-45c4-abe5-5832a4f4429f', '61dc1309-2165-4126-b929-3a2142a23e55', 'Paciente de 35 anos, com febre de 39°C, sintomas gripais e mialgia intensa, retorna de viagem dos Estados Unidos há uma semana. Na foto enviada, apresenta exantema maculopapular difuso com descamação fina nas palmas das mãos. Qual a principal hipótese e manejo?', 'Dengue – suporte.', 'Sarampo – notificação e vitamina A.', 'Febre tifoide – ceftriaxona.', 'Sífilis secundária – penicilina benzatina.', NULL, 'b', 'O quadro de febre alta, pródromos catarrais (tosse, coriza, conjuntivite - não descritos, mas inferidos pelo contexto de exantema febril) e um exantema maculopapular craniocaudal (que pode envolver palmas e plantas e apresentar descamação fina) é altamente sugestivo de sarampo, uma doença de alta transmissibilidade e de notificação compulsória imediata. A história de viagem para uma região com possíveis surtos reforça a suspeita. O tratamento inclui suporte e administração de Vitamina A para reduzir a morbimortalidade.', 'medium', 'TELEINFECTOLOGIA', 'd3f43101-e5f2-408d-bdca-330d7eafb5ac');
